@Service
class ProductSearchService {
    private final RestHighLevelClient client;
    private final SearchQueryRepository searchQueryRepository;

    public ProductSearchService(RestHighLevelClient client, SearchQueryRepository searchQueryRepository) {
        this.client = client;
        this.searchQueryRepository = searchQueryRepository;
    }

    public ProductDocument indexProduct(ProductIndexRequest request) throws IOException {
        ProductDocument document = new ProductDocument(
                request.getId() != null ? request.getId() : UUID.randomUUID().toString(),
                request.getName(),
                request.getDescription(),
                request.getBrand(),
                request.getCategory(),
                request.getTags() != null ? request.getTags() : Collections.emptyList(),
                request.getPrice(),
                request.getRating(),
                request.getAvailable(),
                new Date()
        );
        IndexRequest indexRequest = new IndexRequest(ProductDocument.INDEX_NAME)
                .id(document.getId())
                .source(toJson(document), XContentType.JSON);
        client.index(indexRequest, RequestOptions.DEFAULT);
        return document;
    }

    public List<ProductDocument> bulkIndexProducts(List<ProductIndexRequest> requests) throws IOException {
        BulkRequest bulkRequest = new BulkRequest();
        List<ProductDocument> docs = new ArrayList<>();
        for (ProductIndexRequest request : requests) {
            ProductDocument document = new ProductDocument(
                    request.getId() != null ? request.getId() : UUID.randomUUID().toString(),
                    request.getName(),
                    request.getDescription(),
                    request.getBrand(),
                    request.getCategory(),
                    request.getTags() != null ? request.getTags() : Collections.emptyList(),
                    request.getPrice(),
                    request.getRating(),
                    request.getAvailable(),
                    new Date()
            );
            docs.add(document);
            bulkRequest.add(new IndexRequest(ProductDocument.INDEX_NAME)
                    .id(document.getId())
                    .source(toJson(document), XContentType.JSON));
        }
        BulkResponse response = client.bulk(bulkRequest, RequestOptions.DEFAULT);
        if (response.hasFailures()) {
            throw new IOException("Bulk indexing failed: " + response.buildFailureMessage());
        }
        return docs;
    }

    public SearchResultResponse searchProducts(SearchRequestDto request, String userId, String sessionId) throws IOException {
        if (StringUtils.hasText(request.getQuery())) {
            SearchQueryDocument queryDocument = new SearchQueryDocument(
                    UUID.randomUUID().toString(),
                    request.getQuery(),
                    userId,
                    sessionId,
                    new Date()
            );
            searchQueryRepository.save(queryDocument);
        }

        SearchRequest searchRequest = new SearchRequest(ProductDocument.INDEX_NAME);
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();

        BoolQueryBuilder boolQuery = QueryBuilders.boolQuery();

        if (StringUtils.hasText(request.getQuery())) {
            boolQuery.must(QueryBuilders.multiMatchQuery(request.getQuery(), "name", "description", "tags", "brand", "category")
                    .type(MatchQueryBuilder.Type.BEST_FIELDS));
        } else {
            boolQuery.must(QueryBuilders.matchAllQuery());
        }

        if (StringUtils.hasText(request.getCategory())) {
            boolQuery.filter(QueryBuilders.termQuery("category", request.getCategory()));
        }
        if (StringUtils.hasText(request.getBrand())) {
            boolQuery.filter(QueryBuilders.termQuery("brand", request.getBrand()));
        }
        if (request.getAvailable() != null) {
            boolQuery.filter(QueryBuilders.termQuery("available", request.getAvailable()));
        }
        if (request.getMinPrice() != null || request.getMaxPrice() != null) {
            boolQuery.filter(QueryBuilders.rangeQuery("price")
                    .from(request.getMinPrice() != null ? request.getMinPrice() : 0.0)
                    .to(request.getMaxPrice() != null ? request.getMaxPrice() : Double.MAX_VALUE));
        }

        sourceBuilder.query(boolQuery);
        sourceBuilder.from(Math.max(request.getPage(), 0) * Math.max(request.getSize(), 1));
        sourceBuilder.size(Math.max(request.getSize(), 1));

        sourceBuilder.aggregation(AggregationBuilders.terms("brands").field("brand"));
        sourceBuilder.aggregation(AggregationBuilders.terms("categories").field("category"));
        sourceBuilder.aggregation(AggregationBuilders.terms("availability").field("available"));
        sourceBuilder.aggregation(AggregationBuilders.terms("price_ranges").field("price"));

        searchRequest.source(sourceBuilder);

        SearchResponse response = client.search(searchRequest, RequestOptions.DEFAULT);

        List<ProductDocument> products = new ArrayList<>();
        for (SearchHit hit : response.getHits().getHits()) {
            products.add(fromJson(hit.getSourceAsString()));
        }

        Map<String, List<FacetBucket>> facets = new HashMap<>();
        facets.put("brands", toFacetBuckets(response.getAggregations().get("brands")));
        facets.put("categories", toFacetBuckets(response.getAggregations().get("categories")));
        facets.put("availability", toFacetBuckets(response.getAggregations().get("availability")));
        facets.put("price_ranges", toFacetBuckets(response.getAggregations().get("price_ranges")));

        return new SearchResultResponse(products, response.getHits().getTotalHits() != null ? response.getHits().getTotalHits().value : products.size(), facets);
    }

    private List<FacetBucket> toFacetBuckets(org.elasticsearch.search.aggregations.Aggregation aggregation) {
        if (aggregation == null) {
            return Collections.emptyList();
        }
        Terms terms = (Terms) aggregation;
        List<FacetBucket> buckets = new ArrayList<>();
        for (Terms.Bucket bucket : terms.getBuckets()) {
            buckets.add(new FacetBucket(String.valueOf(bucket.getKey()), bucket.getDocCount()));
        }
        return buckets;
    }

    private String toJson(ProductDocument document) {
        StringBuilder sb = new StringBuilder();
        sb.append("{");
        appendJsonField(sb, "id", document.getId()).append(",");
        appendJsonField(sb, "name", document.getName()).append(",");
        appendJsonField(sb, "description", document.getDescription()).append(",");
        appendJsonField(sb, "brand", document.getBrand()).append(",");
        appendJsonField(sb, "category", document.getCategory()).append(",");
        sb.append("\"tags\":").append(toJsonArray(document.getTags())).append(",");
        appendJsonField(sb, "price", document.getPrice()).append(",");
        appendJsonField(sb, "rating", document.getRating()).append(",");
        appendJsonField(sb, "available", document.getAvailable()).append(",");
        appendJsonField(sb, "createdAt", document.getCreatedAt() != null ? document.getCreatedAt().getTime() : null);
        sb.append("}");
        return sb.toString();
    }

    private ProductDocument fromJson(String json) {
        return new ProductDocument();
    }

    private StringBuilder appendJsonField(StringBuilder sb, String key, Object value) {
        sb.append("\"").append(escape(key)).append("\":");
        if (value == null) {
            sb.append("null");
        } else if (value instanceof Number || value instanceof Boolean) {
            sb.append(value);
        } else {
            sb.append("\"").append(escape(String.valueOf(value))).append("\"");
        }
        return sb;
    }

    private String toJsonArray(List<String> values) {
        if (values == null) return "[]";
        return values.stream()
                .map(v -> "\"" + escape(v) + "\"")
                .collect(Collectors.joining(",", "[", "]"));
    }

    private String escape(String value) {
        return value == null ? "" : value.replace("\\", "\\\\").replace("\"", "\\\"");
    }
}

@RestController
@RequestMapping("/api/products")
class ProductController {
    private final ProductSearchService productSearchService;

    public ProductController(ProductSearchService productSearchService) {
        this.productSearchService = productSearchService;
    }

    @PostMapping
    public ResponseEntity<ProductDocument> indexProduct(@RequestBody ProductIndexRequest request) throws IOException {
        return ResponseEntity.status(HttpStatus.CREATED).body(productSearchService.indexProduct(request));
    }

    @PostMapping("/bulk")
    public ResponseEntity<List<ProductDocument>> bulkIndex(@RequestBody List<ProductIndexRequest> requests) throws IOException {
        return ResponseEntity.status(HttpStatus.CREATED).body(productSearchService.bulkIndexProducts(requests));
    }

    @PostMapping("/search")
    public ResponseEntity<SearchResultResponse> search(@RequestBody SearchRequestDto request,
                                                       @RequestHeader(value = "X-User-Id", required = false) String userId,
                                                       @RequestHeader(value = "X-Session-Id", required = false) String sessionId) throws IOException {
        return ResponseEntity.ok(productSearchService.searchProducts(request, userId, sessionId));
    }
}

